&Error = 0 &DataVazia.SetEmpty() &mode= TrnMode.Insert //######################## Pega configurações de Parâmetro ############################################# Do 'GETConfig'
//######################## Inicio transferência com validação de parâmetros ############################ If Not &PlanCod.IsEmpty() AND NOT &DstPlanCod.IsEmpty() // Valida se plano de contas não é vazio (ORIGEM)) //######################################################### ORIGEM ########################################################################################################## //######################## PEGA CÓDIGO SEQUENCIAL CAPA ORIGEM ################################################# UltimoCodigoEmpresa.Call(domParCod.MOVIMENTO, &EmpCod, 0,&OriMovCod)
//######################## Grava capa do Movimento de Transferência (ORIGEM) ########################### New EmpCod = &EmpCod // Empresa Código MovCod = &OriMovCod // Movimento Código MovDoc = iif(&MovDoc.IsEmpty(), trim(&OriMovCod.ToString()),&MovDoc)// Movimento Nro Documento MovDtaPgt = &MovDtaPgt // Movimento Data Lançamento MovDta = SErverDate() MovHor = ServerNow() // Movimento Data e Hora Lançamento MovCtaBanCod = &OriCtaBanCod // Movimento Conta Bancária MovCreDeb = 'D' MovDtaCon = &MovDtaPgt // Movimento Data de Conferência MovTip = TipoMovimento.Transferencia MovSts = Status_Caixa.Lancado When Duplicate &Error = 1 Return EndNew
//######################## PEGA CÓDIGO SEQUENCIAL CAPA DESTINO################################################# UltimoCodigoEmpresa.Call(domParCod.MOVIMENTO, &EmpCod, 0,&MovCod)
//######################### Grava MOvimento Item ###################################################### RetornaNomeContaBancaria.Call(&EmpCod, &DstCtaBanCod, &CtaBanCodNom) New EmpCod = &EmpCod // Empresa Código MovCod = &OriMovCod // MOvimento Código MovItmCod = 1 // Movimento Item Código PlanCod = &PlanCod MovItmVlr = &MovItmVlr // MOvimento Item Valor MovItmCpl = 'LÇTO ORIGEM! CONTA DST: '+ trim(str(&DstCtaBanCod)) + ' ' +&CtaBanCodNom.Trim()+ iif(not &MovItmCpl.IsEmpty() ,' CPL: '+ &MovItmCpl.Trim(), '') MovCreFilCod = 0 MovCreCod = 0 MovCrePagCod = 0 MovTrnOriCod = &MovCod MovTrnOriCodItm = 1
if &ConciliarCreditoDebitoNenhum = 'D' MovItmIsCon = status_SimNao.Sim MovItmDtaCon = &MovDtaPgt MovItmDoc = &MovDoc endif EndNew
//######################################################### DESTINO ########################################################################################################## //######################## Grava capa do Movimento de Transferência (DESTINO) ########################### New EmpCod = &EmpCod // Empresa Código MovCod = &MovCod // Movimento Código MovDoc = iif(&DstMovDoc.IsEmpty(),trim(&MovCod.ToString()),&DstMovDoc)// Movimento Nro Documento MovDtaPgt = &MovDtaPgt // Movimento Data Lançamento MovDta = SErverDate() MovCreDeb = 'C' MovHor = ServerNow() // Movimento Data e Hora Lançamento MovCtaBanCod = &DstCtaBanCod // Movimento Conta Bancária MovDtaCon = &MovDtaPgt // Movimento Data de Conferência MovTip = TipoMovimento.Transferencia MovSts = Status_Caixa.Lancado When duplicate &Error = 1 return EndNew
//######################### Grava Movimento Item ###################################################### RetornaNomeContaBancaria.Call(&EmpCod, &OriCtaBanCod, &CtaBanCodNom) New EmpCod = &EmpCod // Empresa Código MovCod = &MovCod // MOvimento Código MovItmCod = 1 // Movimento Item Código PlanCod = &DstPlanCod MovItmVlr = &MovItmVlr // MOvimento Item Valor
MovItmCpl = 'LÇTO DESTINO! CONTA ORI: '+ trim(str(&OriCtaBanCod)) +' ' + &CtaBanCodNom.Trim() + iif(not &MovItmCpl.IsEmpty() ,' CPL: '+ &MovItmCpl.Trim(), '') MovCreFilCod = 0 MovCreCod = 0 MovCrePagCod = 0 MovTrnOriCod = &OriMovCod MovTrnOriCodItm = 1 if &ConciliarCreditoDebitoNenhum = 'C' MovItmIsCon = status_SimNao.Sim MovItmDtaCon = &MovDtaPgt MovItmDoc = &MovDoc endif EndNew
//######################### FIM ####################################################################### If &Error = 0 Commit EndIf Do 'AtualizaSaldoContaOrigem' Do 'AtualizaSaldoContaDestino'
Else &Error = 0 msg('ATENÇÃO! Não existe código do plano de contas cadastrado no parâmetro CONF360 OU CONF362, verifique!)') EndIf
Sub 'AtualizaSaldoContaDestino' if &MovCod > 0 prcAtualizaMovimentoFinanceiro.Call(&EmpCod, &MovCod) Endif
For each Order EmpCod,MovCod Where EmpCod = &EmpCod Where MovCod = &MovCod AtualizaSaldoConta.Call(TrnMode.Insert,EmpCod,MovCtaBanCod,MovDtaCon,MovCreDeb,MovVlr,&DataVazia,0,'')
Exit EndFor EndSub
Sub 'AtualizaSaldoContaOrigem' if &OriMovCod > 0 prcAtualizaMovimentoFinanceiro.Call(&EmpCod, &OriMovCod) Endif
For each Order EmpCod,MovCod,(MovDtaPgt) Where EmpCod = &EmpCod Where MovCod = &OriMovCod AtualizaSaldoConta.Call(TrnMode.Insert,EmpCod,MovCtaBanCod,MovDtaCon,MovCreDeb,MovVlr,&DataVazia,0, '')
Exit EndFor EndSub
Sub 'GETConfig' //######################### Configurações de parâmetro para lançamento de origem (DÉBITO)######### RetornaConfSistema.Call(&EmpCod, &FilCod, domConfSistema.TCon028_PlanoContaPadraoTransOrigem, &PlanHie) // Retorna Código do Planbo de Contas Origem do 'GetPlanoContas' &PlanCod = &auxPlanCod
//######################### Configurações de parâmetro para lançamento de Destino (CRÉDITO) ###### RetornaConfSistema.Call(&EmpCod, &FilCod, domConfSistema.TCon029_PlanoContasTransfDestino, &PlanHie) // Retorna Código do Planbo de Contas Destino do 'GetPlanoContas' &DstPlanCod = &auxPlanCod EndSub
Sub 'GetPlanoContas' &auxPlanCod = 0 For Each Order EmpCod, PlanCod Where EmpCod = &EmpCod Where PlanHie = &PlanHie &auxPlanCod = PlanCod Exit EndFor EndSub
